Sure! Here’s a simple test code for the ESP32 that connects to a Wi-Fi network and prints the IP address:


```cpp
#include <WiFi.h>

const char* ssid = "your_SSID";
const char* password = "your_PASSWORD";

void setup() {
  Serial.begin(115200);
  WiFi.begin(ssid, password);

  while (WiFi.status() != WL_CONNECTED) {
    delay(1000);
    Serial.println("Connecting to WiFi...");
  }

  Serial.println("Connected to WiFi!");
  Serial.print("IP Address: ");
  Serial.println(WiFi.localIP());
}

void loop() {
  // put your main code here, to run repeatedly
}
```

Just replace `your_SSID` and `your_PASSWORD` with your network credentials. Let me know if you need further explanation or details!
